/* on.standard.system.authmenu.mergeMenuAuthMng */
INSERT INTO STB_M_MENU_AUTH_MNG (
  AUTH_ID
, MENU_CD
, READ_YN
, WRITE_YN
, UPDATE_YN
, DELETE_YN
, POPUP_OPEN_YN
, POPUP_READ_YN
, POPUP_WRITE_YN
, POPUP_UPDATE_YN
, POPUP_DELETE_YN
)
VALUES

    (
      #{item.authId}
    , #{item.menuCd}
    , #{item.readYn}
    , #{item.writeYn}
    , #{item.updateYn}
    , #{item.deletYn}
    , #{item.popupOpenYn}
    , #{item.popupReadYn}
    , #{item.popupWiteYn}
    , #{item.popupUpdateYn}
    , #{item.popupDeleteYn}
    )

ON DUPLICATE KEY UPDATE
   READ_YN         = VALUES(READ_YN)
, WRITE_YN         = VALUES(WRITE_YN)
, UPDATE_YN        = VALUES(UPDATE_YN)
, DELETE_YN        = VALUES(DELETE_YN)
, POPUP_OPEN_YN    = VALUES(POPUP_OPEN_YN)
, POPUP_READ_YN    = VALUES(POPUP_READ_YN)
, POPUP_WRITE_YN   = VALUES(POPUP_WRITE_YN)
, POPUP_UPDATE_YN  = VALUES(POPUP_UPDATE_YN)
, POPUP_DELETE_YN  = VALUES(POPUP_DELETE_YN);
